package com.capacitorcommunity.videorecorder;

import android.graphics.Color;
import android.net.Uri;
import android.util.DisplayMetrics;
import android.view.ViewGroup;
import android.view.ViewParent;
import android.widget.FrameLayout;

import com.getcapacitor.JSArray;
import com.getcapacitor.FileUtils;
import com.getcapacitor.JSObject;
import com.getcapacitor.PermissionState;
import com.getcapacitor.annotation.CapacitorPlugin;

import com.getcapacitor.Plugin;
import com.getcapacitor.PluginCall;
import com.getcapacitor.PluginMethod;

import org.json.JSONException;
import org.json.JSONObject;

import java.util.HashMap;
import java.util.Timer;
import java.util.TimerTask;

import androidx.coordinatorlayout.widget.CoordinatorLayout;
import co.fitcom.fancycamera.CameraEventListenerUI;
import co.fitcom.fancycamera.EventType;
import co.fitcom.fancycamera.FancyCamera;
import co.fitcom.fancycamera.PhotoEvent;
import co.fitcom.fancycamera.VideoEvent;

@CapacitorPlugin(
        name = "VideoRecorder",
        permissions = {
            @com.getcapacitor.annotation.Permission(
                alias = "camera",
                strings = { android.Manifest.permission.CAMERA }
            ),
            @com.getcapacitor.annotation.Permission(
                alias = "audio",
                strings = { android.Manifest.permission.RECORD_AUDIO }
            )
        },
        requestCodes = { 868 }
)
public class VideoRecorderPlugin extends Plugin {
    private FancyCamera fancyCamera;
    private PluginCall activeCall;
    private int currentCameraPositionInt = 0; // 0 = BACK, 1 = FRONT
    private Timer audioFeedbackTimer;
    private boolean timerStarted;
    private Integer videoBitrate = 3000000;
    private boolean _isFlashEnabled = false;

    @Override
    public void load() {
        super.load();
        android.util.Log.d("VideoRecorder", "Plugin Loaded - Final v2.0");
    }

    @PluginMethod()
    public void initialize(final PluginCall call) {
        this.activeCall = call;

        getActivity().runOnUiThread(new Runnable() {
            @Override
            public void run() {
                if (fancyCamera != null) {
                    fancyCamera.release();
                    ViewParent p = fancyCamera.getParent();
                    if (p instanceof ViewGroup) {
                        ((ViewGroup) p).removeView(fancyCamera);
                    }
                }

                fancyCamera = new FancyCamera(getContext());
                fancyCamera.setMaxVideoBitrate(videoBitrate);
                fancyCamera.setDisableHEVC(true);

                // HARD-FORCE REAR CAMERA
                fancyCamera.setCameraPosition(0);
                currentCameraPositionInt = 0;

                fancyCamera.setListener(new CameraEventListenerUI() {
                    public void onCameraOpenUI() {
                        android.util.Log.d("VideoRecorder", "Camera Hardware Ready");
                        // Double force rear camera after opening
                        fancyCamera.setCameraPosition(0);
                        if (activeCall != null && activeCall.getMethodName().equals("initialize")) {
                            activeCall.resolve();
                        }
                        updateCameraView();
                    }

                    public void onCameraCloseUI() {
                        stopTimer();
                    }

                    @Override
                    public void onPhotoEventUI(PhotoEvent event) {}

                    @Override
                    public void onVideoEventUI(VideoEvent event) {
                        android.util.Log.d("VideoRecorder", "Event: " + event.getType());

                        if (event.getType() == EventType.INFO &&
                            event.getMessage().contains(VideoEvent.EventInfo.RECORDING_FINISHED.toString())) {

                            if (activeCall != null) {
                                JSObject object = new JSObject();
                                if (event.getFile() != null) {
                                    String path = FileUtils.getPortablePath(getContext(), bridge.getLocalUrl(), Uri.fromFile(event.getFile()));
                                    object.put("videoUrl", path);
                                    activeCall.resolve(object);
                                } else {
                                    activeCall.reject("File error");
                                }
                                activeCall = null;
                            }
                        } else if (event.getType() == EventType.INFO &&
                                   event.getMessage().contains(VideoEvent.EventInfo.RECORDING_STARTED.toString())) {
                            if (activeCall != null && activeCall.getMethodName().contains("start")) {
                                activeCall.resolve();
                            }
                        } else if (event.getType() == EventType.ERROR) {
                            if (activeCall != null) {
                                activeCall.reject(event.getMessage());
                                activeCall = null;
                            }
                        }
                    }
                });

                // Layout logic
                DisplayMetrics metrics = new DisplayMetrics();
                getActivity().getWindowManager().getDefaultDisplay().getMetrics(metrics);
                int screenHeight = metrics.heightPixels;
                int screenWidth = metrics.widthPixels;

                // Split Screen: Top 50% Camera, Bottom 50% Web
                CoordinatorLayout.LayoutParams camParams = new CoordinatorLayout.LayoutParams(screenWidth, screenHeight / 2);
                camParams.topMargin = 0;
                fancyCamera.setLayoutParams(camParams);

                ViewGroup parent = (ViewGroup) bridge.getWebView().getParent();
                parent.addView(fancyCamera, 0, camParams);

                CoordinatorLayout.LayoutParams webParams = new CoordinatorLayout.LayoutParams(screenWidth, screenHeight / 2);
                webParams.topMargin = screenHeight / 2;
                bridge.getWebView().setLayoutParams(webParams);

                fancyCamera.setElevation(10);
                bridge.getWebView().setElevation(10);

                if (fancyCamera.hasPermission() && getPermissionState("audio") == PermissionState.GRANTED) {
                    fancyCamera.start();
                } else {
                    requestPermissions(call);
                }
            }
        });
    }

    @PluginMethod()
    public void start(PluginCall call) {
        this.activeCall = call;
        getActivity().runOnUiThread(() -> {
            if (fancyCamera != null) {
                fancyCamera.setCameraPosition(0); // Force Rear again
                fancyCamera.startRecording();
            }
        });
    }

    @PluginMethod()
    public void stop(PluginCall call) {
        this.activeCall = call;
        getActivity().runOnUiThread(() -> {
            if (fancyCamera != null) {
                fancyCamera.stopRecording();
            } else {
                call.reject("Not init");
            }
        });
    }

    @PluginMethod()
    public void stopRecording(PluginCall call) {
        stop(call);
    }

    private void updateCameraView() {
        getActivity().runOnUiThread(() -> {
            if (fancyCamera != null) {
                fancyCamera.setCameraPosition(0);
                fancyCamera.requestLayout();
            }
        });
    }

    private void startTimer() { /* volume feedback placeholder */ }
    private void stopTimer() { /* volume feedback placeholder */ }
}
